export function nextGeneration(cells: Cell[]): Cell[] {
  const liveKeys = new Set(cells.map(cellKey));
  const liveNeighborCounts = new Map<string, number>();

  for (const cell of cells) {
    for (const neighbor of neighborsOf(cell)) {
      const key = cellKey(neighbor);
      liveNeighborCounts.set(key, (liveNeighborCounts.get(key) ?? 0) + 1);
    }
  }

  const survivesOrIsBorn = (key: string, liveNeighbors: number): boolean =>
    liveNeighbors === 3 || (liveNeighbors === 2 && liveKeys.has(key));

  const nextGen: Cell[] = [];
  for (const [key, count] of liveNeighborCounts) {
    if (survivesOrIsBorn(key, count)) nextGen.push(keyToCell(key));
  }
  return nextGen;
}
